- The query implies a 24-hour window for both alerts and traffic distribution is considered 'recent';
- The health metrics are ordered in descending order based on their measurement time, indicating the most recent metrics are given priority;
- The query aims to provide insights into how traffic is distributed among endpoints that have recently triggered alerts.

- 'state of utter chaos' refers to endpoints with 'is_in_panic' = 1; 
- 'dire warning' refers to alerts with severity = 'critical'; 
- 'under the weather' refers to networks with total_health_percentage < 90.

sql:
SELECT endpoint_name, location, status, ip_address
FROM endpoints
WHERE port = (SELECT MAX(port) FROM endpoints);

SELECT AVG(np.average_latency) AS average_latency
FROM network_performance np
WHERE np.measurement_time BETWEEN '2023-10-01 00:00:00' AND '2023-10-02 23:59:59';

SELECT COUNT(DISTINCT endpoint_id) AS total_panicking_endpoints
FROM health_metrics
WHERE is_in_panic = 1;

SELECT total_health_percentage
FROM network_performance
WHERE packet_loss_rate < 0.05;

SELECT measurement_time
FROM network_performance
WHERE measurement_time BETWEEN (
    SELECT measurement_time FROM network_performance WHERE performance_id = 0
) AND (
    SELECT measurement_time FROM network_performance WHERE performance_id = 1
)
GROUP BY measurement_time
HAVING AVG(total_health_percentage) < 95;
